nonces_store = {}

# --- Helper functions ---

def generate_nonce(address):
    """Generates a unique nonce for a given address."""
    # In a real system, nonces should be truly unique and potentially time-based
    # to prevent replay attacks across long periods.
    # For this example, we'll use a simple UUID.
    import uuid
    nonce = str(uuid.uuid4())
    nonces_store[address.lower()] = nonce # Store nonce associated with the address
    return nonce

def verify_signature(address, signature, original_message):
    """
    Verifies an Ethereum signature against a message and recovers the signer's address.
    """
    try:
        # Encode the message according to EIP-191
        encoded_message = encode_defunct(text=original_message)

        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(
            encoded_message,
            signature=signature
        )

        # Check if the recovered address matches the provided address
        return recovered_address.lower() == address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False

